protected double getInitialDomain(double p) {
    double ret;
    double d = getDenominatorDegreesOfFreedom();
    if (d > 2.0){
       // use mean
       ret = d / (d - 2.0);
     } else if (d < 0) {
      throw new MathIllegalArgumentException(" Degrees of freedom cannot be negative " + d);
   }else{
       // This may lead to some problems, but better than dividing by zero
       ret = 1.0;
   }

    return ret;
}

